import json
import os
import boto3

s3 = boto3.client("s3")
dynamodb = boto3.resource("dynamodb")
sns = boto3.client("sns")
sqs = boto3.client("sqs")

S3_BUCKET = os.environ.get("S3_BUCKET", "your-shared-bucket")
DDB_TABLE = os.environ.get("DDB_TABLE", "your-shared-table")
SNS_TOPIC_ARN = os.environ.get("SNS_TOPIC_ARN", "arn:aws:sns:us-east-1:123456789012:your-shared-topic")
SQS_QUEUE_URL = os.environ.get("SQS_QUEUE_URL", "https://sqs.us-east-1.amazonaws.com/123456789012/your-shared-queue")


def lambda_handler(event, context):
    result = {
        "message": "Lambda executed with shared IAM role",
        "services": {}
    }

    try:
        s3.put_object(
            Bucket=S3_BUCKET,
            Key="lambda-test.json",
            Body=json.dumps({"status": "ok"})
        )
        result["services"]["s3"] = "success"
    except Exception as e:
        result["services"]["s3"] = f"error: {str(e)}"

    try:
        table = dynamodb.Table(DDB_TABLE)
        table.put_item(Item={"pk": "lambda-test", "status": "ok"})
        result["services"]["dynamodb"] = "success"
    except Exception as e:
        result["services"]["dynamodb"] = f"error: {str(e)}"

    try:
        sns.publish(
            TopicArn=SNS_TOPIC_ARN,
            Message=json.dumps({"event": "lambda_test", "status": "ok"})
        )
        result["services"]["sns"] = "success"
    except Exception as e:
        result["services"]["sns"] = f"error: {str(e)}"

    try:
        sqs.send_message(
            QueueUrl=SQS_QUEUE_URL,
            MessageBody=json.dumps({"event": "lambda_test", "status": "ok"})
        )
        result["services"]["sqs"] = "success"
    except Exception as e:
        result["services"]["sqs"] = f"error: {str(e)}"

    return {
        "statusCode": 200,
        "body": json.dumps(result)
    }